{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/CharonSanctions.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class CharonSanctions < Base\n      # ゲームシステムの識別子\n      ID = \"CharonSanctions\"\n\n      # ゲームシステム名\n      NAME = \"カローン・サンクションズ\"\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = \"かろおんさんくしおんす\"\n\n      HELP_MESSAGE = <<~TEXT\n        ■ 判定\n          nCSm>=t ［判定］を行う。成功／不完全成功を判定。（p.111）\n          n: ダイス数\n          m: ［難易度］（省略時 4）\n          t: ［必要成功数］（省略時 1）\n\n        ■ 各種表\n          ET 感情ワード（キャラクター）表（p.120）\n          RT 襲撃表（p.146）\n      TEXT\n\n      def eval_game_system_specific_command(command)\n        action_roll(command) ||\n          roll_tables(command, TABLES)\n      end\n\n      private\n\n      def action_roll(command)\n        parser = Command::Parser.new(\"CS\", round_type: round_type)\n                                .has_prefix_number\n                                .enable_suffix_number\n                                .disable_modifier\n                                .restrict_cmp_op_to(nil, :>=)\n        cmd = parser.parse(command)\n        return nil unless cmd\n\n        times = cmd.prefix_number\n        return nil if times < 1\n\n        required = (cmd.suffix_number || 4).clamp(2, 6)\n        target = cmd.target_number || 1\n\n        dice_list = @randomizer.roll_barabara(times, 6)\n        count = dice_list.count { |i| i >= required }\n\n        result =\n          if count >= target\n            Result.success(\"成功\")\n          else\n            Result.failure(\"不完全成功\")\n          end\n\n        sequence = [\n          \"(\#{cmd})\",\n          \"(\#{times}B6>=\#{required}[>=\#{target}])\",\n          \"[\#{dice_list.join(',')}]\",\n          \"成功数:\#{count}\",\n          result.text\n        ].compact\n\n        result.text = sequence.join(\" ＞ \")\n        result\n      end\n\n      TABLES = {\n        'ET' => DiceTable::D66RangeTable.new(\n          '感情ワード（キャラクター）表',\n          {\n            11..12 => '愛情／あなたは、対象のキャラクターに愛情を抱いています。',\n            13..14 => '家族／あなたは、対象のキャラクターをまるで家族のように感じています。',\n            15..16 => '腐れ縁／あなたは、対象のキャラクターを腐れ縁だとを感じています（または、まるで長年の腐れ縁のように気が合う相手だと感じています）。',\n            21..22 => '師弟／そのキャラクターとは、師弟のような関係だと感じています。',\n            23..24 => '好敵手／そのキャラクターを、好敵手だと感じています。',\n            25..26 => '親近感／あなたは、対象のキャラクターに、親近感を抱いています。',\n            31..32 => '友情／あなたは、対象のキャラクターに、友情を抱いています。',\n            33..34 => '尊敬／あなたは、対象のキャラクターを尊敬しています。',\n            35..36 => '庇護／あなたは、対象のキャラクターを守らなければと感じています。',\n            41..42 => '好感／あなたは、対象のキャラクターに好感を抱いています。',\n            43..44 => '興味／あなたは、対象のキャラクターに興味を抱いています。',\n            45..46 => '感銘／あなたは、対象のキャラクターに感銘を抱いています。',\n            51..52 => '畏怖／あなたは、対象のキャラクターに畏怖を抱いています。',\n            53..54 => '信頼／あなたは、対象のキャラクターに信頼を感じています。',\n            55..56 => '不信感／あなたは、対象のキャラクターに不信感を抱いています。',\n            61..62 => '劣等感／あなたは、対象のキャラクターの能力や容姿、実績などに対し劣等感を抱いています。',\n            63..64 => '後悔／あなたは対象のキャラクターを見ると、後悔の念を思い出します（かつて失った人に似ている、など）。',\n            65..66 => '無関心／あなたは、対象のキャラクターに対して無関心を装っています。しかし本当は無視できない存在であると感じています。',\n          }\n        ),\n        \"RT\" => DiceTable::Table.new(\n          \"襲撃表\",\n          \"1D6\",\n          [\n            \"概要：今回の事件の黒幕が放ったものか、それとも何かで恨みを買ったのか、裏社会の暗殺者たちが襲撃を仕掛けてくる。迎え撃つ必要がある。\\n判定：2人で判定。【機敏(SR+1)】〔†射撃〕／【身体(SR+1)】〔†白兵〕\\n全員が完全成功：敵の迎撃に成功した。襲撃者を放ってきた相手もしばらくは動けないだろう。【AP】+1。\\n1人でも不完全成功：何とか敵を迎撃したが、手傷を負ってしまった。PC全員は【HP】を1d+[SR]点消費する。\",\n            \"概要：あまりにも目立ちすぎたせいか、自分に目を光らせている司法組織の捜査官が追ってきた。戦うわけにもいかない。誰かが囮になってうまく逃げるしかない。\\n判定：1人で判定。【身体(SR+2)】〔運動〕\\n全員が完全成功：うまく追手をまくことができた。しばらくは時間を稼ぐことができるだろう。【AP】+1。\\n1人でも不完全成功：何とか逃げることには成功したが、体力を使い果たした。判定を行ったPCは、[調査フェイズ]終了時まで【身体】の判定で振るダイス数-1d。\",\n            \"概要：偶然、一般市民に非合法の活動をしている場面を目撃される。彼らを巻き込まないためにも、何とか誤魔化した方がいいだろう。\\n判定：全員で判定。【知性(SR)】〔交渉〕\\n全員が完全成功：それらしい理屈をつけて、誤魔化すことができた。機転の利いた対応に、裏社会での評価も上がる。【畏敬】+2。\\n1人でも不完全成功：なんとか誤魔化せたが、相手はいまいち納得できないようだ。今後、彼らの動向にも気を配る必要があるだろう。[不完全成功]だったPCは[調査フェイズ]終了まで【知性】の判定で振るダイス数-1d。\",\n            \"概要：情報を整理しようと集まった瞬間、何者かに襲撃を受ける。出自は不明だが、裏社会の存在で間違いないだろう。迎撃の必要がある。\\n判定：全員で判定。【機敏(SR)】〔†射撃〕／【身体(SR)】〔†白兵〕\\n全員が完全成功：鮮やかに敵を撃退してみせた。【畏敬】+2。\\n1人でも不完全成功：敵を撃退できたものの、手傷を負ってしまった。[不完全成功]だったPCは[調査フェイズ]終了まで【機敏】の判定で振るダイス数-1d。\",\n            \"概要：君の活躍に目をつけ、闇の組織が急な情報収集の仕事を依頼してきた。やむにやまれぬ事情があり、無視することもできない。急いで片付けた方がいいだろう。\\n判定：2人で判定。【知性(SR+1)】〔コンピュータ〕／【機敏(SR+1)】〔操縦〕\\n全員が完全成功：コンピュータやフットワークを活かし、情報を素早く手に入れた。闇社会からの評価も上がる。【畏敬】+2。\\n1人でも不完全成功：仕事は成功させたものの、少し雑なものとなって相手を落胆させてしまう。【畏敬】-1。\",\n            \"概要：カローンのことを嗅ぎ回っているマスコミに、活動現場を見られてしまった。何とか言いくるめて、対処する必要がある。\\n判定：1人で判定。【知性(SR+2)】〔交渉〕\\n全員が完全成功：自分たちはカローンではないと言いくるめることができた。ついでに事件捜査の時間を稼ぐための偽情報をリークすることにも成功する。【AP】+1。\\n1人でも不完全成功：何とか言いくるめることができたが、激しく気力を消耗してしまう。判定を行ったPCは、【EP】-1。\",\n          ]\n        ),\n      }.freeze\n\n      register_prefix('\\d+CS', TABLES.keys)\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:CharonSanctions>", "eval_game_system_specific_command", "command", "$ret_or_1", "self", "action_roll", "roll_tables", "TABLES", "private", "parser", "Command::Parser", "Command", "new", "round_type", "has_prefix_number", "enable_suffix_number", "disable_modifier", "restrict_cmp_op_to", "cmd", "parse", "times", "prefix_number", "<", "1", "required", "suffix_number", "4", "clamp", "2", "6", "target", "target_number", "dice_list", "@randomizer", "roll_barabara", "count", "block in action_roll", "i", "block (2 levels) in action_roll", ">=", "result", "Result", "success", "failure", "sequence", "join", "text", "compact", "text=", "DiceTable::D66RangeTable", "DiceTable", "11", "12", "13", "14", "15", "16", "21", "22", "23", "24", "25", "26", "31", "32", "33", "34", "35", "36", "41", "42", "43", "44", "45", "46", "51", "52", "53", "54", "55", "56", "61", "62", "63", "64", "65", "66", "DiceTable::Table", "freeze", "register_prefix", "keys", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,iBAAL;QAGA,gCAAOA,cAAP;QAGA,oCAAWA,aAAX;QAEA,wCACNA,QADqB,GAErBA,yCAFqB,GAGrBA,aAHqB,GAIrBA,qBAJqB,GAKrBA,uBALqB,GAMrBA,IANqB,GAOrBA,SAPqB,GAQrBA,8BARqB,GASrBA,mBATM;;AAYAC,QAAAA,iDAAAA,6CAAsCC,OAAtCD;AAAAA,UAAAA;;UACE,IAAA,QAAAE,CAAAA,YAAAC,IAAAC,aAAAA,CAAYH,OAAZG,CAAAF,CAAA,CAAA;YAAAF,OAAA;UAAA;YACEA,OAAAG,IAAAE,aAAAA,CAAYJ,OAAZ,EAAqBK,YAArBD;UADF;QADFL,CAAAA;QAKAG,IAAAI,SAAAA,CAAAA;;AAEAH,QAAAA,2BAAAA,uBAAgBH,OAAhBG;AAAAA,UAAAA;;;UACEI,SAASC,IAAAC,aAAAD,WAAeE,KAAAA,CAAKP,IAApB,EAA0B,wBAAA,cAAYD,IAAAS,YAAAA,CAAAA,CAAZ,EAAXD,CACAE,mBAAAA,CAAAA,CACAC,sBAAAA,CAAAA,CACAC,kBAAAA,CAAAA,CACAC,oBAAAA,CAAoB,GAJnC,EAIwC,IAAzBA;UACxBC,MAAMT,MAAMU,OAAAA,CAAOjB,OAAPiB;UACZ,KAAA,QAAkBD,GAAlB,CAAA;YAAA,OAAO;UAAP;UAEAE,QAAQF,GAAGG,eAAAA,CAAAA;UACX,IAAA,QAAoBC,OAANF,KAAME,EAAEC,CAAFD,CAApB,CAAA;YAAA,OAAO;UAAP;UAEAE,WAAY,CAAA,QAAArB,CAAAA,YAAAe,GAAGO,eAAAA,CAAAA,CAAHtB,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAqBuB,CAArB,CAAA,CAAuBC,OAAAA,CAAOC,CAA/B,EAAkCC,CAAVF;UACnCG,SAAS,CAAA,QAAA3B,CAAAA,YAAAe,GAAGa,eAAAA,CAAAA,CAAH5B,CAAA,CAAA,GAAA,CAAA,SAAA,IAAA,CAAqBoB,CAArB,CAAA;UAETS,YAAYC,eAAWC,eAAAA,CAAed,KAA1B,EAAiCS,CAAtBK;UACvBC,QAAiBA,MAATH,SAASG,SAAAA,EAAAA,EAAAA,EAATC,aAAmBC,CAAnBD;;YAAmB;YAAGE,OAAEC,OAAFF,CAAEE,EAAGf,QAAHe,EAAxBH,CAASD;UAEjBK,SACE,CAAA,QAASD,OAANJ,KAAMI,EAAGT,MAAHS,CAAT,CAAA,GAAA,CACEE,YAAMC,SAAAA,CAASrC,IAATqC,CADR,IAAA,CAGED,YAAME,SAAAA,CAAStC,OAATsC,CAHR,CAAA;UAMFC,WAAW,CACRvC,GAAD,GAAA,CAAIa,GAAJ,CAAA,GAAQb,GADC,EAERA,GAAD,GAAA,CAAIe,KAAJ,CAAA,GAAUf,MAAV,GAAA,CAAgBmB,QAAhB,CAAA,GAAyBnB,KAAzB,GAAA,CAA8ByB,MAA9B,CAAA,GAAqCzB,IAF5B,EAGRA,GAAD,GAAA,CAAI2B,SAASa,MAAAA,CAAMxC,GAANwC,CAAb,CAAA,GAAwBxC,GAHf,EAIRA,MAAD,GAAA,CAAO8B,KAAP,CAJS,EAKTK,MAAMM,MAAAA,CAAAA,CALG,CAMVC,SAAAA,CAAAA;UAEDP,MAAMQ,UAAAA,CAAQJ,QAAQC,MAAAA,CAAMxC,KAANwC,CAAhBG;UACN3C,OAAAmC;QAlCFnC,CAAAA;QAqCA,kCAAS,sBAAA,MACC4C,IAAAC,eAAAD,kBAAwBrC,KAAAA,CAC9BZ,gBADM,EAEN,MACE,OAAAmD,EAAA,EAAIC,EAAJ,QADF,EACYpD,8BADZ,EAEE,OAAAqD,EAAA,EAAIC,EAAJ,QAFF,EAEYtD,oCAFZ,EAGE,OAAAuD,EAAA,EAAIC,EAAJ,QAHF,EAGYxD,mEAHZ,EAIE,OAAAyD,EAAA,EAAIC,EAAJ,QAJF,EAIY1D,iCAJZ,EAKE,OAAA2D,EAAA,EAAIC,EAAJ,QALF,EAKY5D,4BALZ,EAME,OAAA6D,EAAA,EAAIC,EAAJ,QANF,EAMY9D,iCANZ,EAOE,OAAA+D,EAAA,EAAIC,EAAJ,QAPF,EAOYhE,+BAPZ,EAQE,OAAAiE,EAAA,EAAIC,EAAJ,QARF,EAQYlE,4BARZ,EASE,OAAAmE,EAAA,EAAIC,EAAJ,QATF,EASYpE,kCATZ,EAUE,OAAAqE,EAAA,EAAIC,EAAJ,QAVF,EAUYtE,8BAVZ,EAWE,OAAAuE,EAAA,EAAIC,EAAJ,QAXF,EAWYxE,8BAXZ,EAYE,OAAAyE,EAAA,EAAIC,EAAJ,QAZF,EAYY1E,8BAZZ,EAaE,OAAA2E,EAAA,EAAIC,EAAJ,QAbF,EAaY5E,8BAbZ,EAcE,OAAA6E,EAAA,EAAIC,EAAJ,QAdF,EAcY9E,8BAdZ,EAeE,OAAA+E,EAAA,EAAIC,EAAJ,QAfF,EAeYhF,gCAfZ,EAgBE,OAAAiF,EAAA,EAAIC,EAAJ,QAhBF,EAgBYlF,6CAhBZ,EAiBE,OAAAmF,EAAA,EAAIC,EAAJ,QAjBF,EAiBYpF,oDAjBZ,EAkBE,OAAAqF,EAAA,EAAIC,EAAJ,QAlBF,EAkBYtF,4DAlBZ,CAF8BY,CADzB,EAAA,MAwBC2E,IAAArC,eAAAqC,UAAgB3E,KAAAA,CACtBZ,KADM,EAENA,KAFM,EAGN,CACEA,0NADF,EAEEA,wOAFF,EAGEA,8PAHF,EAIEA,mNAJF,EAKEA,0OALF,EAMEA,gOANF,CAHsBY,CAxBjB,EAoCR4E,QAAAA,CAAAA,CApCD;QAsCAxF,OAAAI,IAAAqF,iBAAAA,CAAgBzF,QAAhB,EAAyBO,YAAMmF,MAAAA,CAAAA,CAA/BD;MAxGFzF,GAAAA,WAAAA,EAAwB2F,UAAxB3F;IADFD,GAAAA,WAAAA;EADFD,GAAAA,WAAAA;AAFAD;"}}]}